import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import "./EventsList.css";

const EventsList = () => {
  const navigate = useNavigate();

  const [events, setEvents] = useState([]);
  const [search, setSearch] = useState("");
  const [category, setCategory] = useState("all");
  const [location, setLocation] = useState("");

  useEffect(() => {
    fetch("http://localhost:5000/events")
      .then(res => res.json())
      .then(data => {
        if (Array.isArray(data)) setEvents(data);
        else setEvents([]);
      })
      .catch(err => console.error("Fetch error:", err));
  }, []);

  const filteredEvents = Array.isArray(events)
    ? events.filter(event => {
        const searchValue = search.toLowerCase();
        const locationValue = location.toLowerCase();

        const matchesSearch = event.title
          ?.toLowerCase()
          .includes(searchValue);

        const matchesCategory =
          category === "all" || event.category === category;

        const matchesLocation = event.location
          ?.toLowerCase()
          .includes(locationValue);

        // 🔥 логика (универсальная)
        return (
          (search ? matchesSearch : true) &&
          (category !== "all" ? matchesCategory : true) &&
          (location ? matchesLocation : true)
        );
      })
    : [];

  const handleClick = (id) => navigate(`/events/${id}`);

  return (
    <div className="events-container">
      <h2>Події</h2>

      <div className="filter-form">

        {/* 🔹 категория */}
        <select
          value={category}
          onChange={(e) => setCategory(e.target.value)}
        >
          <option value="all">Всі категорії</option>
          <option value="IT">IT</option>
          <option value="Business">Business</option>
          <option value="Design">Design</option>
          <option value="Marketing">Marketing</option>
          <option value="Education">Education</option>
        </select>

        {/* 🔹 поиск */}
        <input
          type="text"
          placeholder="Пошук події..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />

        {/* 🔥 новый фильтр по городу */}
        <input
          type="text"
          placeholder="Місто (наприклад: Berlin)"
          value={location}
          onChange={(e) => setLocation(e.target.value)}
        />

        <button
          onClick={() => {
            setSearch("");
            setCategory("all");
            setLocation("");
          }}
        >
          Очистити
        </button>
      </div>

      <div className="events-grid">
        {filteredEvents.length > 0 ? (
          filteredEvents.map(event => (
            <div
              key={event.id}
              className="event-card"
              onClick={() => handleClick(event.id)}
            >
              <h3>{event.title}</h3>
              <p>{event.description}</p>
              <span>📍 {event.location}</span>
              <br />
              <span>📅 {new Date(event.date).toLocaleString()}</span>
            </div>
          ))
        ) : (
          <p className="no-results">Подій не знайдено :(</p>
        )}
      </div>
    </div>
  );
};

export default EventsList;
